function solve(digitSum) {
    const MOD = 1000000007;
    const MAX_VAL = 5000;

    /**
     * Calculates the sum of digits of a number.
     * @param {number} n
     * @returns {number}
     */
    const getDigitSum = (n) => {
        let sum = 0;
        let strN = String(n);
        for (let i = 0; i < strN.length; i++) {
            sum += parseInt(strN[i]);
        }
        return sum;
    };

    // 1. Preprocessing: Find candidates for each required digit sum D (0 <= D <= 50)
    // Candidates[D] stores a boolean array/map indicating if x is a valid number for digit sum D.
    // Since MAX_VAL is small (5000), we use arrays of size MAX_VAL + 1.
    const candidates = Array(51).fill(0).map(() => Array(MAX_VAL + 1).fill(false));

    for (let x = 0; x <= MAX_VAL; x++) {
        const d = getDigitSum(x);
        if (d <= 50) {
            candidates[d][x] = true;
        }
    }

    const N = digitSum.length;

    // DP Initialization (i = 0)
    // dpPrev[x] stores the number of valid prefixes ending in x for the previous index.
    let dpPrev = new Array(MAX_VAL + 1).fill(0);
    const D0 = digitSum[0];

    if (D0 >= 0 && D0 <= 50) {
        for (let x = 0; x <= MAX_VAL; x++) {
            if (candidates[D0][x]) {
                dpPrev[x] = 1;
            }
        }
    } else {
        // If D0 is out of bounds (shouldn't happen based on constraints, but safe check)
        return 0;
    }

    // DP Iteration (i = 1 to N-1)
    for (let i = 1; i < N; i++) {
        let dpCurr = new Array(MAX_VAL + 1).fill(0);
        const Di = digitSum[i];

        if (Di < 0 || Di > 50) {
            return 0; // Impossible requirement
        }

        // 1. Calculate Prefix Sum P based on dpPrev
        // P[k] = Sum(dpPrev[j] for j=0 to k)
        const P = new Array(MAX_VAL + 1).fill(0);
        let currentSum = 0;
        for (let k = 0; k <= MAX_VAL; k++) {
            currentSum = (currentSum + dpPrev[k]) % MOD;
            P[k] = currentSum;
        }

        // 2. Calculate dpCurr
        // dpCurr[x] = P[x] if x is a valid candidate for Di, else 0.
        for (let x = 0; x <= MAX_VAL; x++) {
            if (candidates[Di][x]) {
                // Since P[x] already accumulates sums of all valid previous states y <= x,
                // this directly gives the count of valid sequences ending at x.
                dpCurr[x] = P[x];
            }
        }

        dpPrev = dpCurr;
    }

    // Final Result: Sum of all elements in the final DP state
    let totalCount = 0;
    for (let x = 0; x <= MAX_VAL; x++) {
        totalCount = (totalCount + dpPrev[x]) % MOD;
    }

    return totalCount;
}

